class Solution:
    def wordPattern(self, pattern: str, s: str) -> bool:
        words = defaultdict(int)
        for word in s.split():
            words[word] += 1

        patset = defaultdict(int)
        for ch in pattern:
            patset[ch] += 1

        validate = defaultdict(int)
        for nums in words.values():
            validate[nums] += 1
        for nums in patset.values():
            validate[nums] -= 1

        return not any(value != 0 for value in validate.values())

class Solution:
    def wordPattern(self, pattern: str, s: str) -> bool:
        set1 = defaultdict(int)
        set2 = defaultdict(int)
        words = s.split()

        for i in range(len(pattern)):
            if words[i] not in set1:
                set1[words[i]] = i

            if pattern[i] not in set2:
                set2[pattern[i]] = i

            if set1[words[i]] != set2[pattern[i]]:
                return False

        return True

class Solution:
    def wordPattern(self, pattern: str, s: str) -> bool:
        set1 = defaultdict(int)
        set2 = defaultdict(int)
        words = s.split()
        if len(words) != len(pattern):
            return False

        for i in range(len(pattern)):
            if words[i] not in set1:
                set1[words[i]] = i

            if pattern[i] not in set2:
                set2[pattern[i]] = i

            if set1[words[i]] != set2[pattern[i]]:
                return False

        return True
